// mm/src/utils/fileStore.js
// Stores File blobs in IndexedDB so we can recover after navigating to Register/Login.
// ✅ Fix: ensure object store exists (and support legacy store name "files")

const DB_NAME = 'mm_workflow_db';
const DB_VERSION = 2; // ✅ bump version so onupgradeneeded runs
const STORE = 'workflow_files';
const LEGACY_STORE = 'files';

function openDb() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);

    req.onupgradeneeded = () => {
      const db = req.result;

      // ✅ current store
      if (!db.objectStoreNames.contains(STORE)) {
        db.createObjectStore(STORE, { keyPath: 'id' });
      }

      // ✅ legacy store (older uploadStep.js used this)
      if (!db.objectStoreNames.contains(LEGACY_STORE)) {
        db.createObjectStore(LEGACY_STORE, { keyPath: 'id' });
      }
    };

    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

function txDone(tx) {
  return new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
    tx.onabort = () => reject(tx.error);
  });
}

function pickExistingStore(db, preferred) {
  if (db.objectStoreNames.contains(preferred)) return preferred;
  if (db.objectStoreNames.contains(LEGACY_STORE)) return LEGACY_STORE;
  return preferred; // will throw later (but upgrade should prevent this)
}

// Save/update one file record
export async function saveWorkflowFile(record) {
  if (!record?.id) throw new Error('saveWorkflowFile requires record.id');
  if (!record?.file) throw new Error('saveWorkflowFile requires record.file');

  const db = await openDb();
  const storeName = pickExistingStore(db, STORE);

  const tx = db.transaction(storeName, 'readwrite');
  tx.objectStore(storeName).put({
    id: record.id,
    name: record.name || record.file?.name || 'file',
    tag: record.tag || 'Main Manuscript',
    type: record.file?.type || '',
    size: record.file?.size || 0,
    file: record.file,
    savedAt: Date.now(),
  });

  await txDone(tx);
  db.close();
}

// Remove one by id
export async function removeWorkflowFile(id) {
  if (!id) return;

  const db = await openDb();

  // delete from both stores if they exist
  const stores = [];
  if (db.objectStoreNames.contains(STORE)) stores.push(STORE);
  if (db.objectStoreNames.contains(LEGACY_STORE)) stores.push(LEGACY_STORE);

  if (stores.length === 0) {
    db.close();
    return;
  }

  const tx = db.transaction(stores, 'readwrite');
  for (const s of stores) tx.objectStore(s).delete(id);

  await txDone(tx);
  db.close();
}

// Load all stored files
export async function loadWorkflowFiles() {
  const db = await openDb();

  const storeName = pickExistingStore(db, STORE);
  const tx = db.transaction(storeName, 'readonly');
  const store = tx.objectStore(storeName);

  const req = store.getAll();

  const items = await new Promise((resolve, reject) => {
    req.onsuccess = () => resolve(req.result || []);
    req.onerror = () => reject(req.error);
  });

  await txDone(tx);
  db.close();

  return (items || []).map((x) => ({
    id: x.id,
    name: x.name,
    tag: x.tag,
    file: x.file,
    type: x.type,
    size: x.size,
  }));
}

// Clear everything
export async function clearWorkflowFiles() {
  const db = await openDb();

  const stores = [];
  if (db.objectStoreNames.contains(STORE)) stores.push(STORE);
  if (db.objectStoreNames.contains(LEGACY_STORE)) stores.push(LEGACY_STORE);

  if (stores.length === 0) {
    db.close();
    return;
  }

  const tx = db.transaction(stores, 'readwrite');
  for (const s of stores) tx.objectStore(s).clear();

  await txDone(tx);
  db.close();
}
